from collections import defaultdict
from typing import Any

# Safe dict access patterns
config = {"timeout": 30, "retries": 3}
print(config.get("model", "gpt-4"))     # "gpt-4" — default if missing

# Dict comprehension to filter and transform
raw = {"a": 1, "b": None, "c": 3, "d": None}
clean = {k: v for k, v in raw.items() if v is not None}
print(clean)   # {'a': 1, 'c': 3}

# Group-by with defaultdict
messages = [
    {"role": "user", "content": "Hello"},
    {"role": "assistant", "content": "Hi!"},
    {"role": "user", "content": "How are you?"},
]
by_role = defaultdict(list)
for msg in messages:
    by_role[msg["role"]].append(msg["content"])
print(dict(by_role))
# {'user': ['Hello', 'How are you?'], 'assistant': ['Hi!']}

# Merging config layers
base   = {"timeout": 30, "model": "gpt-4", "verbose": False}
env    = {"timeout": 60}
user   = {"verbose": True}
final  = base | env | user   # Python 3.9+
print(final)
# {'timeout': 60, 'model': 'gpt-4', 'verbose': True}

d = {"a": 1, "b": 2, "c": 3}

# WRONG: RuntimeError in Python 3
try:
    for key in d:
        if d[key] < 2:
            del d[key]
except RuntimeError as e:
    print(e)

# CORRECT: iterate over copy of keys
for key in list(d.keys()):
    if d[key] < 2:
        del d[key]

# BETTER: dict comprehension
d = {"a": 1, "b": 2, "c": 3}
d = {k: v for k, v in d.items() if v >= 2}
print(d)  # {'b': 2, 'c': 3}
